from pyspark.sql import SparkSession, DataFrame
from pyspark.sql.types import StringType, StructField, StructType

def get_flatten_schema(distribute_on_type):
    if distribute_on_type:
        flattenedFields = [
            StructField("JSON_Name", StringType(), nullable=False),
            StructField("JSON_ValueString", StringType(), nullable=True),
            StructField("JSON_ValueInt", StringType(), nullable=True),
            StructField("JSON_ValueFloat", StringType(), nullable=True),
            StructField("JSON_ValueBool", StringType(), nullable=True)
        ]
    else:
        flattenedFields = [
            StructField("JSON_Name", StringType(), nullable=False),
            StructField("JSON_ValueString", StringType(), nullable=True)
        ]
    return flattenedFields

def flatten_json(obj, prefix='', distribute_on_type=True):
    rows = []

    def add_row(name, value):
        row = {"JSON_Name": name}
        if distribute_on_type:
            row["JSON_ValueString"] = str(value) if isinstance(value, str) else None
            row["JSON_ValueInt"] = str(value) if isinstance(value, int) else None
            row["JSON_ValueFloat"] = str(value) if isinstance(value, float) else None
            row["JSON_ValueBool"] = str(value).lower() if isinstance(value, bool) else None
        else:
            row["JSON_ValueString"] = str(value)
        rows.append(row)

    def recurse(obj, prefix=""):
        if isinstance(obj, dict):
            for k, v in obj.items():
                recurse(v, f"{prefix}.{k}" if prefix else k)
        elif isinstance(obj, list):
            for i, v in enumerate(obj):
                recurse(v, f"{prefix}.{i}")
        else:
            add_row(prefix, obj)

    recurse(obj)
    return rows

def get_flattened_dataframe(df: DataFrame, column_name: str, distribute_on_type: bool):
    all_flattened_rows = []
    import json
    for row in df.collect():
        parsed_json = json.loads(row[column_name])
        flattened = flatten_json(parsed_json, distribute_on_type=distribute_on_type)

        row_data = row.asDict()
        for flat_row in flattened:
            combined_row = {**row_data, **flat_row}
            all_flattened_rows.append(combined_row)
    return all_flattened_rows

distribute_on_type = False
include_in_output = False

spark = SparkSession.builder.appName("JSONStringDataFrame").getOrCreate()
df = in0

flattenedFields = get_flatten_schema(distribute_on_type=distribute_on_type)
all_flattened_rows = get_flattened_dataframe(df, column_name="Field_1", distribute_on_type=distribute_on_type)
originalFields = df.schema.fields
if not include_in_output:
    originalFields = [f for f in originalFields if f.name != "Field_1"]
    all_flattened_rows = [
        {k: v for k, v in row.items() if k != "Field_1"}
        for row in all_flattened_rows
    ]

newSchema = StructType(originalFields + flattenedFields)
out0 = spark.createDataFrame(all_flattened_rows, schema=newSchema)
